def valid_date(date):
    # Rule 1: The date string is not empty
    if not date:
        return False

    # Check if the format is mm-dd-yyyy (exactly two dashes)
    parts = date.split('-')
    if len(parts) != 3:
        return False

    mm, dd, yyyy = parts

    # Check if each part consists only of digits
    if not (mm.isdigit() and dd.isdigit() and yyyy.isdigit()):
        return False

    # Convert to integers
    try:
        month = int(mm)
        day = int(dd)
        year = int(yyyy)
    except ValueError:
        return False

    # Rule 3: The months should not be less than 1 or higher than 12
    if month < 1 or month > 12:
        return False

    # Rule 2: Check days based on month
    if month in [1, 3, 5, 7, 8, 10, 12]:
        # Months with 31 days
        if day < 1 or day > 31:
            return False
    elif month in [4, 6, 9, 11]:
        # Months with 30 days
        if day < 1 or day > 30:
            return False
    elif month == 2:
        # February - max 29 days (simplified check, doesn't account for leap years)
        if day < 1 or day > 29:
            return False

    # Additional check: ensure leading zeros are properly formatted (though not strictly required)
    # But we need to ensure the format is exactly mm-dd-yyyy, so check lengths
    if len(mm) != 2 or len(dd) != 2 or len(yyyy) != 4:
        return False

    return True
