    if not date:
        return False

    # Check if the format is mm-dd-yyyy (exactly 10 characters with two dashes)
    if len(date) != 10 or date[2] != '-' or date[5] != '-':
        return False

    # Split the date into parts
    parts = date.split('-')
    if len(parts) != 3:
        return False

    month_str, day_str, year_str = parts

    # Check if all parts are numeric
    if not (month_str.isdigit() and day_str.isdigit() and year_str.isdigit()):
        return False

    # Convert to integers
    try:
        month = int(month_str)
        day = int(day_str)
        year = int(year_str)
    except ValueError:
        return False

    # Rule 3: Months should be between 1 and 12
    if month < 1 or month > 12:
        return False

    # Rule 2: Validate days based on month
