```python
def split_words(txt):
    # Check if there are whitespaces
    if ' ' in txt:
        return txt.split()

    # Check if there are commas
    elif ',' in txt:
        return txt.split(',')

    # If neither whitespaces nor commas exist, count lowercase letters with odd order
    else:
        count = 0
        for char in txt:
            if 'a' <= char <= 'z':
                # ord('a') = 97, but we want ord('a') = 0, ord('b') = 1, etc.
                # So subtract ord('a') to get 0-based index
                if (ord(char) - ord('a')) % 2 == 1:
                    count += 1
        return count
```

