def fix_spaces(text):
    result = []
    i = 0
    while i < len(text):
        if text[i] != ' ':
            result.append(text[i])
            i += 1
        else:
            # Count consecutive spaces
            space_count = 0
            j = i
            while j < len(text) and text[j] == ' ':
                space_count += 1
                j += 1

            # Replace based on count
            if space_count > 2:
                result.append('-')
            else:
                result.append('_' * space_count)

            i = j

    return ''.join(result)
```
